<template>
  <div class="submit-form">
    <button
      class="buttonAdd"
      @click="openAdd = !openAdd"
      :class="openAdd == false ? 'closed' : ''"
    ></button>
    <h4>Поиск рецепта</h4>
    <div v-if="openAdd">
      <div v-if="!submitted">
        <div class="form-group">
          <label for="name">Название</label>
          <input
            type="text"
            class="form-control"
            id="name"
            v-model="tutorial.name"
            name="name"
          />
        </div>
        <div class="form-group">
          <label for="products">Продукты</label>
          <input
            type="text"
            class="form-control"
            id="products"
            v-model="tutorial.products"
            name="products"
          />
        </div>
        
        <button @click="searchTutorial" class="btn btn-success">искать</button>
      </div>

      <div v-else>
        <h4>Успешно добавлено!</h4>
        <button class="btn btn-success" @click="newTutorial">
          Добавить еще
        </button>
      </div>
    </div>
  </div>
</template>

<script>
import TutorialDataService from "@/services/ReciepesDataService";

export default {
  name: "search-tutorial",
  data() {
    return {
      tutorial: {
        name: "",
        description: "",
        products: "",
        steps: "",
      },
      submitted: false,
      openAdd: false,
    };
  },
  methods: {
    searchTutorial() {
      var data = {
        name: this.tutorial.name,
        description: this.tutorial.description,
        products: this.tutorial.products,
        steps: this.tutorial.steps,
      };

      TutorialDataService.search(data)
        .then(() => {
          console.log(data);
          this.submitted = true;
        })
        .catch((e) => {
          console.log(e);
        });
    },

    newTutorial() {
      this.submitted = false;
      this.tutorial = {
        name: "",
        description: "",
        products: "",
      };
    },
  },
};
</script>

<style>
.submit-form {
  max-width: 300px;
  margin: auto;
}
</style>
