<template>
  <div @click="telegramLink(url, { text })">
    <i class="fab fa-telegram"></i>
  </div>
</template>

<script>
import objectToGetParams from "../utils/objectToGetParams";
export default {
  name: "telegram-vue",
  methods: {
    telegramLink(url, { text }) {
      window.open(
        "https://telegram.me/share/" +
          objectToGetParams({
            url: url,
            text: text,
          }),
        "__blank"
      );
    },
  },
  props: {
    url: {
      required: false,
      type: String,
    },
    text: {
      required: true,
      type: String,
    },
    scale: {
      required: false,
      type: String,
    },
  },
};
</script>
